const https = require('https');
const childProcess = require('child_process');

module.exports = async function (context, req) {
  const inputFilename = req.body.inputFilename;
  const outputFormat = req.body.outputFormat;

  if (!inputFilename || !outputFormat) {
    context.res = {
      status: 400,
      body: 'Please provide both input filename and output format'
    };
    return;
  }

  const libreOfficeCommand = `libreoffice --headless --convert-to ${outputFormat} ${inputFilename}`;

  childProcess.exec(libreOfficeCommand, (error, stdout, stderr) => {
    if (error) {
      context.res = {
        status: 500,
        body: `Error while converting file: ${error}`
      };
      return;
    }

    const outputFilename = `${inputFilename}.${outputFormat}`;

    context.res = {
      status: 200,
      body: `Successfully converted ${inputFilename} to ${outputFilename}`
    };
  });
};